import{_ as t,o as e,c as n,a1 as s}from"./chunks/framework.CMt7O7Ol.js";const b=JSON.parse('{"title":"日内交易基础课：科学建仓","description":"","frontmatter":{},"headers":[],"relativePath":"trading/intraday-entry/index.md","filePath":"trading/intraday-entry/index.md"}'),i={name:"trading/intraday-entry/index.md"};function d(r,a,l,p,o,c){return e(),n("div",null,[...a[0]||(a[0]=[s(`<h1 id="日内交易基础课-科学建仓" tabindex="-1">日内交易基础课：科学建仓 <a class="header-anchor" href="#日内交易基础课-科学建仓" aria-label="Permalink to &quot;日内交易基础课：科学建仓&quot;">​</a></h1><p>这套课程不以任何一位交易者的个人风格为中心，而是把多种成熟的日内操作经验整理成一套可以观察、执行和复盘的建仓流程。</p><blockquote><p>核心目标：把“我觉得会涨跌”，改写成“价格在什么位置、出现什么行为、在哪里证明判断错误”。</p></blockquote><h2 id="统一建仓框架" tabindex="-1">统一建仓框架 <a class="header-anchor" href="#统一建仓框架" aria-label="Permalink to &quot;统一建仓框架&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>位置 → 触发 → 确认 → 失效 → 目标</span></span></code></pre></div><table tabindex="0"><thead><tr><th>环节</th><th>要回答的问题</th></tr></thead><tbody><tr><td>位置</td><td>价格是否到达事先标记的关键区域？</td></tr><tr><td>触发</td><td>突破、拒绝、收回或结构改变是否已经出现？</td></tr><tr><td>确认</td><td>市场最终接受在关键位的哪一侧？</td></tr><tr><td>失效</td><td>什么价格行为能够明确证明判断错误？</td></tr><tr><td>目标</td><td>下一结构位能否提供足够的盈亏比？</td></tr></tbody></table><h2 id="当前章节" tabindex="-1">当前章节 <a class="header-anchor" href="#当前章节" aria-label="Permalink to &quot;当前章节&quot;">​</a></h2><ol><li><a href="./01-scientific-entry-framework.html">第一章：科学建仓的基本框架</a></li><li><a href="./02-premarket-map-and-opening-regimes.html">第二章：盘前地图与开盘环境分类</a></li><li><a href="./03-breakout-retest-and-failed-breakout.html">第三章：突破回踩与失败突破</a></li><li><a href="./04-risk-stop-and-position-sizing.html">第四章：止损、风险与仓位设计</a></li></ol><h2 id="建议学习顺序" tabindex="-1">建议学习顺序 <a class="header-anchor" href="#建议学习顺序" aria-label="Permalink to &quot;建议学习顺序&quot;">​</a></h2><p>先用第一章建立统一语言，再用第二章练习盘前画图与开盘分类，最后用第三章反复识别“突破被接受”和“突破被拒绝”。</p><p>每次复盘只记录六项：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>关键位置：</span></span>
<span class="line"><span>触发行为：</span></span>
<span class="line"><span>确认行为：</span></span>
<span class="line"><span>结构失效：</span></span>
<span class="line"><span>第一目标：</span></span>
<span class="line"><span>实际结果与偏差：</span></span></code></pre></div><p>后续章节将继续补充持仓与退出、复盘与迭代。</p><blockquote><p>本课程用于交易教育和个人研究，不构成投资建议。图例仅用于解释结构，不能直接视为实时买卖信号。</p></blockquote>`,14)])])}const u=t(i,[["render",d]]);export{b as __pageData,u as default};
